  handleCastError,
  handleDuplicateError,
  handleValidationError,
  handleZodError,
};

import { NextFunction, Request, Response } from 'express';
import httpStatus from 'http-status';
import jwt, { JwtPayload } from 'jsonwebtoken';
import config from '../config';
import AppError from '../errors/AppError';
import { TUserRole } from '../modules/user/user.interface';
import { User } from '../modules/user/user.model';
import catchAsync from '../utils/catchAsync';

const auth = (...requiredRoles: TUserRole[]) => {
    return catchAsync(async (req: Request, res: Response, next: NextFunction) => {
        const token = req.headers.authorization;

        // checking if the token is missing
        if (!token) {
            throw new AppError(httpStatus.UNAUTHORIZED, 'You are not authorized!');
        }

        // checking if the given token is valid
        let decoded;
        try {
            decoded = jwt.verify(
                token,
                config.jwt_access_secret as string,
            ) as JwtPayload;
        } catch (err) {
            throw new AppError(httpStatus.UNAUTHORIZED, 'Unauthorized');
        }

        const { role, userId, iat } = decoded;

        // checking if the user is exist
        const user = await User.findById(userId);

        if (!user) {
            throw new AppError(httpStatus.NOT_FOUND, 'This user is not found !');
        }
        // checking if the user is already deleted
        const isDeleted = user?.isDeleted;

        if (isDeleted) {
            throw new AppError(httpStatus.FORBIDDEN, 'This user is deleted !');
        }

        // checking if the user is blocked
        // const userStatus = user?.status;

        // if (userStatus === 'blocked') {
        //   throw new AppError(httpStatus.FORBIDDEN, 'This user is blocked ! !');
        // }

        if (requiredRoles && !requiredRoles.includes(role)) {
            throw new AppError(
                httpStatus.UNAUTHORIZED,
                'You are not authorized  hi!',
            );
        }

        req.user = decoded as JwtPayload;
        next();
    });
};

export default auth;

import { NextFunction, Request, Response } from 'express';
import { ZodObject } from 'zod';
import catchAsync from '../utils/catchAsync';

const validateRequest = (schema: ZodObject<any>) => {
  return catchAsync(async (req: Request, res: Response, next: NextFunction) => {
    await schema.parseAsync({
      body: req.body,
      cookies: req.cookies,
    });

    next();
  });
};

export default validateRequest;

import nodemailer from 'nodemailer';
import config from '../../config';

const transporter = nodemailer.createTransport({
    host: 'smtp.mailgun.org', // Replace with your SMTP host
    port: 587,
    secure: false, // true for 465, false for other ports
    auth: {
        user: config.mailgun_smtp_user,
        pass: config.mailgun_smtp_password,
    },
});

export const sendEmail = async (to: string, subject: string, text: string, attachments?: any[]) => {
    try {
        const info = await transporter.sendMail({
            from: config.mailgun_from_email_address || '"Visa Portal" <noreply@example.com>',
            to,
            subject,
            text,
            attachments,
        });

        console.log('Message sent: %s', info.messageId);
        return info;
    } catch (error) {
        console.error('Error sending email: ', error);
        // In production, we might want to throw or log to a service
    }
};

