import SSLCommerzPayment from 'sslcommerz-lts';
import config from '../../../config';
import { IPaymentGatewayService, IPaymentInitiateParams } from '../payment.utils';

export class SslCommerzPaymentService implements IPaymentGatewayService {
    private sslcommerz: typeof SSLCommerzPayment;

    constructor() {
        this.sslcommerz = new SSLCommerzPayment(
            config.sslcommerz_store_id!,
            config.sslcommerz_store_passwd!,
            config.sslcommerz_is_live
        );
    }

    async initiatePayment(params: IPaymentInitiateParams): Promise<{ paymentUrl: string | null; transactionId: string; gatewayResponse: any }> {
        const data = {
            total_amount: params.amount,
            currency: params.currency,
            tran_id: params.transactionId, // use unique tran_id for each api call
            success_url: params.successUrl,
            fail_url: params.failUrl,
            cancel_url: params.cancelUrl,
            ipn_url: params.successUrl, // We can reuse success url or define a specific IPN endpoint
            shipping_method: 'Courier',
            product_name: `Payment for Application ${params.applicationId}`,
            product_category: 'Visa Application',
            product_profile: 'general',
            cus_name: params.clientName,
            cus_email: params.clientEmail,
            cus_add1: 'Dhaka',
            cus_add2: 'Dhaka',
            cus_city: 'Dhaka',
            cus_state: 'Dhaka',
            cus_postcode: '1000',
            cus_country: 'Bangladesh',
            cus_phone: '01711111111',
            cus_fax: '01711111111',
            ship_name: params.clientName,
            ship_add1: 'Dhaka',
            ship_add2: 'Dhaka',
            ship_city: 'Dhaka',
            ship_state: 'Dhaka',
            ship_postcode: 1000,
            ship_country: 'Bangladesh',
        };

        const response = await this.sslcommerz.init(data);

        return {
            paymentUrl: response?.GatewayPageURL || null,
            transactionId: params.transactionId,
            gatewayResponse: response
        };
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    async verifyPayment(transactionId: string, gatewayResponse: any): Promise<boolean> {
        // SSLCommerz webhook/IPN usually sends 'VALID' as status for successful payments.
        // Also we could hit the order validation API using tran_id, but usually checking IPN data is sufficient securely.
        // Assuming gatewayResponse is the POST body returned to the success URL by SSLCommerz

        // In actual production, we should validate it using the validate API from SSLCommerz 
        // or by checking the hash/signature.

        return gatewayResponse?.status === 'VALID' || gatewayResponse?.status === 'VALIDATED';
    }
}

